  if(rm)rc=e(rm[1]);
  var ds=au+(rc?' 回复:'+rc:'');
  d.push({title:ti,desc:ds,url:$('hiker://empty#noHistory#').rule(function(detailUrl,postTitle){
    var H='https://t66y.com/',hh=fetchPC(detailUrl,{headers:{'User-Agent':PC_UA,'Referer':H}})||'',r=[];
    function de(s){return String(s||'').replace(/&amp;/gi,'&').replace(/&quot;/gi,'"').replace(/&#0?39;|&apos;/gi,"'").replace(/&lt;/gi,'<').replace(/&gt;/gi,'>').replace(/&nbsp;|&#160;/gi,' ').replace(/&#(\d+);/g,function(a,n){return String.fromCharCode(parseInt(n))})}
