    function at(t,n){var m=String(t||'').match(new RegExp('(?:^|\\s)'+n+'\\s*=\\s*(["\\\'])([\\s\\S]*?)\\1','i'));return m?m[2]:''}
    var sm=hh.match(/<div\s+class=["']tpc_content[^"']*["'][^>]*id=["']conttpc["'][^>]*>/i),body='';
    if(sm){var tail=hh.slice(sm.index+sm[0].length),em=tail.search(/<br\s*\/?><br\s*\/?>\s*<div[^>]+onclick=["']clickLike|<\/div>\s*<\/td>\s*<\/tr>\s*<\/table>\s*<\/th>/i);body=em>-1?tail.slice(0,em):tail}
    var text=body.replace(/<script[\s\S]*?<\/script>/gi,'').replace(/<style[\s\S]*?<\/style>/gi,'').replace(/<br\s*\/?>|<\/p>|<\/div>|<\/li>|<hr[^>]*>/gi,'\n').replace(/<[^>]+>/g,' ');text=de(text).replace(/[ \t]+\n/g,'\n').replace(/\n[ \t]+/g,'\n').replace(/\n{3,}/g,'\n\n').replace(/[ \t]{2,}/g,' ').trim();
    r.push({title:'“'+postTitle+'”',url:'hiker://empty',col_type:'text_1'});
    if(text)r.push({title:text,url:'hiker://empty',col_type:'long_text'});
    var imgs=[],seen={},ir=/<img\b[^>]*>/ig,im;
    while((im=ir.exec(body))){var tag=im[0],p=at(tag,'ess-data')||at(tag,'data-src')||at(tag,'data-original')||at(tag,'src');p=abs(p);if(p&&!seen[p]){seen[p]=1;imgs.push(p)}}
    for(var i=0;i<imgs.length;i++)r.push({title:'图片 '+(i+1)+' / '+imgs.length,pic_url:imgs[i],img:imgs[i],url:imgs[i],col_type:'pic_1_full'});
    if(!text&&imgs.length==0)r.push({title:'暂无正文或图片',desc:detailUrl,url:detailUrl,col_type:'text_1'});
    setResult(r)
  },l,ti),col_type:'text_1'})
}
if(d.length==0)d.push({title:'未找到帖子',desc:U,col_type:'text_1'});
